    pan_card: panNumber, mobile,
    'employment.emp_type': 'SELFEMP', 'employment.income': 50000,
    'employment.business_type': 'Proprietorship',
    business_name: DECOY_BUSINESS_NAME,   // matches bank name — must be ignored
    annual_turnover: 'Rs.0 to 40 lakhs',
    nature_of_business: 'Trader / Wholesaler / Retailer',
    // no GSTIN — forces no-GSTIN secondary path (checks ALL soft-pull names)
};
const payload = await JsonUtils.modifyPayload(patch, base);
const createR = await API.apiRequest(constants.baseURI2, 'post', constants.pathInit, payload, fkHeaders);
if (createR.statusCode !== 200) throw new Error(`App create failed: ${createR.statusCode}`);
appId = createR.body?.response?.application_id;
if (!appId) throw new Error('No appId');
addContext(this, { title: 'TC-08 App Create (decoy business_name)', value: createR.body });
for (let i = 1; i <= 3; i++) {
    const { offerStatus } = await triggerOfferForApp(appId);
    if (offerStatus === 'Approved') break;
    if (i < 3) appId = null; // create fresh app if rejected
}
bankData = await advanceToPennyStage(appId, this);

